import React, { useState } from 'react';
import main_page from '../css/main_page.module.css';

import Header from './components/Header';
import LeftMenu from './components/LeftMenu';
import DashboardContent from './components/DashboardContent';
import MyTasksContent from './components/MyTasksContent';
// Припустімо, що у вас є також VitalTaskContent та інші

const MainPage = () => {
    // 1. Стан для відстеження активного пункту меню
    const [activeMenuItem, setActiveMenuItem] = useState('dashboard');

    // 2. Функція, яка викликається при натисканні на пункт меню
    const handleMenuItemClick = (key) => {
        // Оновлюємо стан, що спричинить перерендеринг та зміну контенту
        setActiveMenuItem(key);
        console.log(`Навігація до: ${key}`);
    };
    
    const handleLogout = () => {
        console.log('Користувач вийшов!');
        // ...
    };

    // 3. Функція, що повертає потрібний компонент контенту
    const renderContent = () => {
        switch (activeMenuItem) {
            case 'dashboard':
                return <DashboardContent />;
            case 'my-task':
                return <MyTasksContent />;
            // Додайте тут інші пункти меню (наприклад, 'vital-task')
            /*
            case 'vital-task':
                return <VitalTaskContent />; 
            */
            default:
                return <DashboardContent />; // Запасний контент
        }
    };

    return (
        <>
            <Header /> 
            <div className={main_page.main_page}>
                <LeftMenu 
                    activeItem={activeMenuItem}
                    onMenuItemClick={handleMenuItemClick}
                    onLogout={handleLogout}
                />
                
                {/* 4. Умовний Рендеринг: Викликаємо функцію для відображення контенту */}
                <main className={main_page['main-content-area']}>
                    {renderContent()}
                </main>
            </div>
        </>
    );
};

export default MainPage;
